2629 static Value *foldSelectWithFrozenICmp(SelectInst &Sel, InstCombiner::BuilderTy &Builder) {
2630   FreezeInst *FI = dyn_cast<FreezeInst>(Sel.getCondition());
2631   if (!FI)
2632     return nullptr;
2633 
2634   Value *Cond = FI->getOperand(0);
2635   Value *TrueVal = Sel.getTrueValue(), *FalseVal = Sel.getFalseValue();
2636 
2637   //   select (freeze(x == y)), x, y --> y
2638   //   select (freeze(x != y)), x, y --> x
2639   // The freeze should be only used by this select. Otherwise, remaining uses of
2640   // the freeze can observe a contradictory value.
2641   //   c = freeze(x == y)   ; Let's assume that y = poison & x = 42; c is 0 or 1
2642   //   a = select c, x, y   ;
2643   //   f(a, c)              ; f(poison, 1) cannot happen, but if a is folded
2644   //                        ; to y, this can happen.
2645   CmpInst::Predicate Pred;
2646   if (FI->hasOneUse() &&
2647       match(Cond, m_c_ICmp(Pred, m_Specific(TrueVal), m_Specific(FalseVal))) &&
2648       (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE)) {
2649     return Pred == ICmpInst::ICMP_EQ ? FalseVal : TrueVal;
2650   }
2651 
2652   return nullptr;
2653 }
