1852 /// Fold icmp (and X, Y), C.
1853 Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
1854                                                    BinaryOperator *And,
1855                                                    const APInt &C) {
1856   if (Instruction *I = foldICmpAndConstConst(Cmp, And, C))
1857     return I;
