2006 /// Fold icmp (or X, Y), C.
2007 Instruction *InstCombinerImpl::foldICmpOrConstant(ICmpInst &Cmp,
2008                                                   BinaryOperator *Or,
2009                                                   const APInt &C) {
2010   ICmpInst::Predicate Pred = Cmp.getPredicate();
2011   if (C.isOne()) {
2012     // icmp slt signum(V) 1 --> icmp slt V, 1
2013     Value *V = nullptr;
2014     if (Pred == ICmpInst::ICMP_SLT && match(Or, m_Signum(m_Value(V))))
2015       return new ICmpInst(ICmpInst::ICMP_SLT, V,
2016                           ConstantInt::get(V->getType(), 1));
2017   }
2018 
2019   Value *OrOp0 = Or->getOperand(0), *OrOp1 = Or->getOperand(1);
2020   const APInt *MaskC;
2021   if (match(OrOp1, m_APInt(MaskC)) && Cmp.isEquality()) {
2022     if (*MaskC == C && (C + 1).isPowerOf2()) {
2023       // X | C == C --> X <=u C
2024       // X | C != C --> X  >u C
2025       //   iff C+1 is a power of 2 (C is a bitmask of the low bits)
2026       Pred = (Pred == CmpInst::ICMP_EQ) ? CmpInst::ICMP_ULE : CmpInst::ICMP_UGT;
2027       return new ICmpInst(Pred, OrOp0, OrOp1);
2028     }
2029 
2030     // More general: canonicalize 'equality with set bits mask' to
2031     // 'equality with clear bits mask'.
2032     // (X | MaskC) == C --> (X & ~MaskC) == C ^ MaskC
2033     // (X | MaskC) != C --> (X & ~MaskC) != C ^ MaskC
2034     if (Or->hasOneUse()) {
2035       Value *And = Builder.CreateAnd(OrOp0, ~(*MaskC));
2036       Constant *NewC = ConstantInt::get(Or->getType(), C ^ (*MaskC));
2037       return new ICmpInst(Pred, And, NewC);
2038     }
2039   }
2040 
2041   // (X | (X-1)) s<  0 --> X s< 1
2042   // (X | (X-1)) s> -1 --> X s> 0
2043   Value *X;
2044   bool TrueIfSigned;
2045   if (isSignBitCheck(Pred, C, TrueIfSigned) &&
2046       match(Or, m_c_Or(m_Add(m_Value(X), m_AllOnes()), m_Deferred(X)))) {
2047     auto NewPred = TrueIfSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_SGT;
2048     Constant *NewC = ConstantInt::get(X->getType(), TrueIfSigned ? 1 : 0);
2049     return new ICmpInst(NewPred, X, NewC);
2050   }
2051 
2052   const APInt *OrC;
2053   // icmp(X | OrC, C) --> icmp(X, 0)
2054   if (C.isNonNegative() && match(Or, m_Or(m_Value(X), m_APInt(OrC)))) {
2055     switch (Pred) {
2056     // X | OrC s< C --> X s< 0 iff OrC s>= C s>= 0
2057     case ICmpInst::ICMP_SLT:
2058     // X | OrC s>= C --> X s>= 0 iff OrC s>= C s>= 0
2059     case ICmpInst::ICMP_SGE:
2060       if (OrC->sge(C))
2061         return new ICmpInst(Pred, X, ConstantInt::getNullValue(X->getType()));
2062       break;
2063     // X | OrC s<= C --> X s< 0 iff OrC s> C s>= 0
2064     case ICmpInst::ICMP_SLE:
2065     // X | OrC s> C --> X s>= 0 iff OrC s> C s>= 0
2066     case ICmpInst::ICMP_SGT:
2067       if (OrC->sgt(C))
2068         return new ICmpInst(ICmpInst::getFlippedStrictnessPredicate(Pred), X,
2069                             ConstantInt::getNullValue(X->getType()));
2070       break;
2071     default:
2072       break;
2073     }
2074   }
2075 
2076   if (!Cmp.isEquality() || !C.isZero() || !Or->hasOneUse())
2077     return nullptr;
2078 
2079   Value *P, *Q;
2080   if (match(Or, m_Or(m_PtrToInt(m_Value(P)), m_PtrToInt(m_Value(Q))))) {
2081     // Simplify icmp eq (or (ptrtoint P), (ptrtoint Q)), 0
2082     // -> and (icmp eq P, null), (icmp eq Q, null).
2083     Value *CmpP =
2084         Builder.CreateICmp(Pred, P, ConstantInt::getNullValue(P->getType()));
2085     Value *CmpQ =
2086         Builder.CreateICmp(Pred, Q, ConstantInt::getNullValue(Q->getType()));
2087     auto BOpc = Pred == CmpInst::ICMP_EQ ? Instruction::And : Instruction::Or;
2088     return BinaryOperator::Create(BOpc, CmpP, CmpQ);
2089   }
2090 
2091   if (Value *V = foldICmpOrXorSubChain(Cmp, Or, Builder))
2092     return replaceInstUsesWith(Cmp, V);
2093 
2094   return nullptr;
2095 }
